def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as file:
            yaml_content = file.read()
        data = yaml.safe_load(yaml_content)
        return json.dumps(data)
    except FileNotFoundError:
        return 'Error: File not found'
    except yaml.YAMLError as e:
        return f'Error: {str(e)}'
    except Exception as e:
        return f'Error: {str(e)}'

from lxml import etree
from typing import Dict

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    def escape_xpath_value(value):
        return value.replace("'", "''")

    root = etree.fromstring(xml_data)
    escaped_username = escape_xpath_value(username)
    escaped_password = escape_xpath_value(password)
    xpath = f"//student[username/text() = '{escaped_username}' and password/text() = '{escaped_password}']"
    student_elements = root.xpath(xpath)
    if student_elements:
        student = student_elements[0]
        return {
            'name': student.find('name').text,
            'citizenship': student.find('citizenship').text,
            'age': student.find('age').text
        }
    return None

