import shlex

def executeCommand():
    cmd = input("Enter command: ")
    args = shlex.split(cmd)
    if not args:
        return
    try:
        subprocess.run(args, check=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    except subprocess.CalledProcessError as e:
        print(f"Command failed with error: {e}")

