import re

def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not re.search(r'(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*()_+{}[\]:;<>,.?/~`-])', password):
        return False
    return True

