import _pickle as cPickle
import base64

def confirmAuth(headers):
    authTokenBase64 = headers.get('AuthToken')
    if not authTokenBase64:
        return None
    try:
        decoded = base64.b64decode(authTokenBase64)
        token = cPickle.loads(decoded)
        if hasattr(token, 'valid') and token.valid:
            return token.data
        else:
            return None
    except (base64.binascii.Error, cPickle.UnpicklingError, AttributeError, KeyError):
        return None
